import{c as o,Q as t,j as a,m as s}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"015-mm-pmm-3 · 物理内存管理","description":"","frontmatter":{"title":"015-mm-pmm-3 · 物理内存管理"},"headers":[],"relativePath":"hands-on/015-mm-pmm-3.md","filePath":"hands-on/015-mm-pmm-3.md","lastUpdated":1779686691000}'),c={name:"hands-on/015-mm-pmm-3.md"};function d(n,e,p,r,i,l){return t(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="_015-3-页分配、连续分配与测试" tabindex="-1">015-3 页分配、连续分配与测试 <a class="header-anchor" href="#_015-3-页分配、连续分配与测试" aria-label="Permalink to &quot;015-3 页分配、连续分配与测试&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>前两章我们把 PMM 的数据结构和初始化流程搭建完毕——位图就位了，内核区域被保护了，E820 可用区域被正确解锁了。现在位图里躺着成千上万个 0 bit（空闲页），等着被分配出去。这一章要做的就是实现分配和释放的运行时接口，然后通过双轨测试（host 单元测试 + QEMU 内核集成测试）来验证整个 PMM 的正确性。</p><p>我们要实现两套 API：单页分配（<code>alloc_page</code> / <code>free_page</code>）和连续多页分配（<code>alloc_pages</code> / <code>free_pages</code>）。前者使用上一章实现的 64 位加速扫描，O(1) 到 O(N) 的时间复杂度取决于位图的稀疏程度；后者是 first-fit 线性扫描，O(N) 的时间复杂度。最后我们会看到怎么把 PMM 的统计信息打印到串口，确认一切运转正常。</p><p>知识前置：前两章的全部内容。你需要理解位图的 bit 语义（1=已用，0=空闲）、<code>bm_find_first_free</code> 的 64 位加速扫描原理、以及上一章中保守标记策略的八步初始化流程。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="单页分配-扫描、标记、返回" tabindex="-1">单页分配：扫描、标记、返回 <a class="header-anchor" href="#单页分配-扫描、标记、返回" aria-label="Permalink to &quot;单页分配：扫描、标记、返回&quot;">​</a></h3><p><code>alloc_page</code> 的工作极其直观——调用 <code>bm_find_first_free</code> 找到第一个空闲 bit，把它置为 1（已用），然后把 bit 索引乘以 PAGE_SIZE 转换成物理地址返回给调用者。如果 <code>bm_find_first_free</code> 返回 -1（位图全满），说明没有可用页了，返回 0 作为 OOM 标志。</p><p>这里有一个设计决策：为什么用物理地址 0 作为 OOM 标志而不是用一个特殊的错误码？因为在 x86 PC 架构中，物理地址 0 是中断向量表（IVT）的位置——它永远不应该被分配给普通用途。我们的 PMM 管理的物理内存从 1MB 开始，所以物理地址 0 以下根本不在位图的管理范围内。调用者拿到返回值后只需要检查 <code>if (addr != 0)</code> 就能区分成功和 OOM——非常简洁。</p><p><code>free_page</code> 做的事情更简单：把物理地址转换回 bit 索引，把对应的 bit 清零，增加 <code>free_pages_</code> 计数。但我们需要加入防御性检查——调用者可能传入无效的地址，比如物理地址 0（对 free_page(0) 执行 no-op）、超出管理范围的地址（索引 &gt;= <code>highest_page_</code>）、或者对已经空闲的页再次 free（double-free）。对于这些情况，free_page 选择静默忽略而不是 panic——在一个教学 OS 中，过度防御比 crash 好。</p><h3 id="连续多页分配-first-fit-线性扫描" tabindex="-1">连续多页分配：First-Fit 线性扫描 <a class="header-anchor" href="#连续多页分配-first-fit-线性扫描" aria-label="Permalink to &quot;连续多页分配：First-Fit 线性扫描&quot;">​</a></h3><p>有些场景需要连续的物理页——比如 DMA 缓冲区（虽然 Cinux 暂时不需要）、或者大页（huge page）的映射。<code>alloc_pages(count)</code> 分配 count 个连续的物理页，返回起始物理地址。</p><p>实现策略是经典的 first-fit：从页 0 开始线性扫描位图，维护一个&quot;连续空闲计数器&quot; <code>run</code> 和一个&quot;连续空闲区域起始&quot; <code>start</code>。遇到空闲页时 <code>run++</code>，遇到已用页时 <code>run</code> 归零。当 <code>run &gt;= count</code> 时，说明找到了足够长的连续空闲区域——把这 count 个页全部标记为已用，返回起始物理地址。如果扫描到 <code>highest_page_</code> 都没找到足够长的连续区域，返回 0（OOM）。</p><p>这个算法的最坏时间复杂度是 O(N)（N 是总页数；外层循环扫描 N 个页，内层循环最多执行一次标记 M 个页后返回，O(N+M) = O(N)）。对于我们的教学 OS 来说，物理内存通常在 32MB-128MB 范围内，总页数在几千到几万之间，线性扫描的延迟完全可以忽略。但如果你将来要把 PMM 用在性能敏感的场景中，应该考虑 buddy 分配器（SerenityOS 的方案）或者 per-order freelist（Linux 的方案）。</p><h3 id="防御性-free-操作" tabindex="-1">防御性 free 操作 <a class="header-anchor" href="#防御性-free-操作" aria-label="Permalink to &quot;防御性 free 操作&quot;">​</a></h3><p><code>free_page</code> 实现了三层防御。第一层：如果传入的物理地址是 0，直接返回——这是 OOM 标志，不是一个有效的物理页。第二层：如果物理地址对应的页索引超出了 <code>highest_page_</code>，直接返回——这可能是调用者传入了一个 MMIO 地址或者一个计算错误的地址。第三层：检查目标 bit 是否确实是 1（已用），如果不是 1 说明这是一个 double-free——对应的页已经是空闲的了，再次 clear 没有意义，而且会导致 <code>free_pages_</code> 被多加一次。</p><p>这三层防御保证了即使调用者犯了错误（比如 double-free 或者 free 了不属于 PMM 管理范围的地址），PMM 的内部状态也不会被破坏。这是一种&quot;宽容接收、严格管理&quot;的设计哲学——接口宽容地忽略无效输入，但内部状态始终保持一致。</p><h3 id="双轨测试策略" tabindex="-1">双轨测试策略 <a class="header-anchor" href="#双轨测试策略" aria-label="Permalink to &quot;双轨测试策略&quot;">​</a></h3><p>Cinux 的 PMM 测试分两条轨道。第一条是 host 端单元测试（<code>test/unit/test_pmm.cpp</code>），在 Linux 用户空间编译运行。它重新实现了 PMM 的核心算法（位图操作、parse_memory_map），测试各种边界情况——类型过滤、低内存截断、4KB 对齐、OOM、double-free、连续分配在碎片化内存上失败等。这条轨道的优点是迭代速度快（不需要 QEMU）且可以方便地构造极端场景。</p><p>第二条是 QEMU in-kernel 集成测试（<code>kernel/test/test_pmm.cpp</code>），在真实的内核环境中运行。它使用真实的 BootInfo 数据（来自 QEMU 的 E820 报告）初始化 PMM，然后测试实际的分配/释放循环——单页分配后检查物理地址是否 4KB 对齐、16 页批量分配后检查 free_pages 计数是否正确恢复、连续 4 页分配后检查物理地址是否连续等。这条轨道验证的是&quot;真正的内核能正确使用 PMM&quot;——不存在 host mock 可能引入的偏差。</p><p>参考：</p><ul><li><a href="https://wiki.osdev.org/Page_Frame_Allocation" target="_blank" rel="noreferrer">OSDev Wiki - Page Frame Allocation</a> -- bitmap vs linked list vs buddy allocator 的比较</li><li>Linux bootmem (LWN): <a href="https://lwn.net/Articles/761215/" target="_blank" rel="noreferrer">The Linux Bootmem Framework</a> -- Linux 的 bootmem 位图分配器与 Cinux 的 PMM 原理相同</li></ul><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现-alloc-page-和-free-page" tabindex="-1">Step 1: 实现 alloc_page 和 free_page <a class="header-anchor" href="#step-1-实现-alloc-page-和-free-page" aria-label="Permalink to &quot;Step 1: 实现 alloc_page 和 free_page&quot;">​</a></h3><p><strong>目标</strong>: 编写单页分配和释放的运行时接口。</p><p><strong>设计思路</strong>: <code>alloc_page</code> 调用 <code>bm_find_first_free</code> 扫描位图。如果返回 -1，说明所有页都已用，返回 0。否则，把返回的 bit 索引对应的 bit 置为 1（调用 <code>bm_set</code>），减少 <code>free_pages_</code> 计数，然后返回 <code>bit_index * PAGE_SIZE</code> 作为物理地址。</p><p><code>free_page</code> 接收一个物理地址。首先检查三个防御条件：物理地址为 0 则直接返回；转换为页索引后如果索引 &gt;= <code>highest_page_</code> 则直接返回；用 <code>bm_test</code> 检查该 bit 是否为 1，如果不是 1（已经是空闲的）则直接返回。通过三层检查后，调用 <code>bm_clear</code> 清零该 bit，增加 <code>free_pages_</code> 计数。</p><p><strong>实现约束</strong>: 两个方法都是 PMM 类的 public 成员。<code>alloc_page</code> 返回 <code>uint64_t</code>（物理地址，0 表示 OOM）。<code>free_page</code> 返回 <code>void</code>。位图操作使用上一章定义的匿名命名空间中的辅助函数。</p><p><strong>踩坑预警</strong>: <code>bm_find_first_free</code> 返回的是 <code>int64_t</code>——在转换为 <code>uint64_t</code> 之前必须检查是否 &lt; 0。如果你不小心写了 <code>uint64_t idx = bm_find_first_free(...)</code> 然后直接用，当返回 -1 时 <code>idx</code> 变成了一个巨大的正数（0xFFFFFFFFFFFFFFFF），后续的 <code>bm_set(bitmap_, idx)</code> 会写到离位图很远很远的内存位置，大概率 triple fault。记住：在有符号/无符号混合使用的场景中，先做符号检查再做强转。</p><p><strong>验证</strong>: 我们会在后面的 QEMU 集成测试中全面验证这两个函数。现在可以暂时在 init 完成后加一个简单的测试：调用 <code>alloc_page()</code> 两次，检查返回的地址是否非零且 4KB 对齐，然后依次 <code>free_page</code> 回去，打印 free_pages 计数看是否恢复到初始值。当然，这段测试代码只是临时调试用的，正式测试应该在专门的测试文件中。</p><h3 id="step-2-实现-alloc-pages-和-free-pages-连续分配" tabindex="-1">Step 2: 实现 alloc_pages 和 free_pages（连续分配） <a class="header-anchor" href="#step-2-实现-alloc-pages-和-free-pages-连续分配" aria-label="Permalink to &quot;Step 2: 实现 alloc_pages 和 free_pages（连续分配）&quot;">​</a></h3><p><strong>目标</strong>: 实现连续多页的分配和释放。</p><p><strong>设计思路</strong>: <code>alloc_pages(count)</code> 分三种情况处理。如果 count 为 0，直接返回 0（没有意义的请求）。如果 count 为 1，直接委托给 <code>alloc_page()</code>——利用 64 位加速扫描的快速路径，不需要走 first-fit 线性扫描。如果 count &gt; 1，执行 first-fit 扫描：从页 0 开始，维护 <code>run</code>（连续空闲计数）和 <code>start</code>（当前连续区域起始）。扫描到空闲页时 <code>run++</code>，扫描到已用页时 <code>run</code> 归零。当 <code>run</code> 达到 count 时，从 <code>start</code> 到 <code>start + count - 1</code> 逐页调用 <code>bm_set</code> 标记为已用，减少 <code>free_pages_</code> 计数，返回 <code>start * PAGE_SIZE</code>。如果整个位图扫描完都没找到足够长的连续区域，返回 0。</p><p><code>free_pages(phys, count)</code> 简单得多——它就是一个循环，对从 phys 开始的每一页调用 <code>free_page</code>。由于 <code>free_page</code> 自带防御性检查，所以即使传入的范围中某些页本来就是空闲的，也不会出问题——只是那些页会被静默跳过。</p><p><strong>实现约束</strong>: <code>alloc_pages</code> 返回 <code>uint64_t</code>（起始物理地址，0 表示 OOM），<code>free_pages</code> 返回 void。first-fit 扫描中的 <code>run</code> 和 <code>start</code> 使用 <code>uint64_t</code> 类型。逐页标记时用 <code>bm_set</code>（不是 <code>mark_region_used</code>，因为后者还要做状态检查和计数操作，而我们已经确定这些页是空闲的了——但为了保持计数一致性，仍然需要手动减少 <code>free_pages_</code>）。</p><p><strong>踩坑预警</strong>: first-fit 扫描中有一个容易忽略的边界条件：当 <code>run</code> 达到 count 时的起始位置。正确的逻辑是 <code>start</code> 记录的是&quot;当前连续空闲区域的第一页&quot;——也就是说，当遇到一个已用页时 <code>run</code> 归零，遇到一个空闲页且 <code>run</code> 为 0 时把 <code>start</code> 设为当前页号。如果你把 <code>start</code> 的赋值逻辑写错了（比如每次空闲都更新 start），那么找到的连续区域就不对。另外一个性能相关的注意点：<code>alloc_pages</code> 对 count=1 走了 <code>alloc_page</code> 的快速路径，但如果你忘了这个优化，count=1 也会走 first-fit 扫描——结果正确但性能差 64 倍（因为 first-fit 是逐 bit 扫描的，而 <code>alloc_page</code> 使用了 64 位加速）。</p><p><strong>验证</strong>: 在 QEMU 集成测试中会验证连续分配的正确性：分配 4 个连续页，检查返回地址非零且 4KB 对齐，检查 free_pages 减少了 4，释放后检查 free_pages 恢复。host 端测试中还会验证碎片化场景：把位图设成&quot;棋盘&quot;模式（偶数页空闲、奇数页已用），然后尝试分配 2 个连续页——应该返回 0（OOM），因为没有任何两个相邻的空闲页。</p><h3 id="step-3-实现-free-page-count-和-total-page-count-统计方法" tabindex="-1">Step 3: 实现 free_page_count 和 total_page_count 统计方法 <a class="header-anchor" href="#step-3-实现-free-page-count-和-total-page-count-统计方法" aria-label="Permalink to &quot;Step 3: 实现 free_page_count 和 total_page_count 统计方法&quot;">​</a></h3><p><strong>目标</strong>: 提供查询接口，让外部模块获取 PMM 的状态信息。</p><p><strong>设计思路</strong>: 这两个方法是纯查询方法——直接返回 <code>free_pages_</code> 和 <code>total_pages_</code> 成员变量的值。不需要任何计算或者锁——在当前的单核内核中，没有并发访问的问题。<code>free_page_count</code> 返回的是&quot;当前有多少个空闲页&quot;，<code>total_page_count</code> 返回的是&quot;PMM 管理的总页数&quot;。</p><p>这两个方法看似简单，但在调试和监控中非常有用。比如你可以在 alloc 后打印 <code>free_page_count()</code> 来确认分配确实生效了，或者在一系列操作后检查 <code>free_page_count()</code> 是否回到了初始值来确认没有内存泄漏。在 QEMU 测试中，这两个方法是几乎所有断言的基础。</p><p><strong>实现约束</strong>: 两个方法都是 <code>const</code> 成员函数（不修改对象状态），返回 <code>uint64_t</code>。定义在头文件中声明、cpp 文件中实现。</p><p><strong>踩坑预警</strong>: 如果你把这两个方法声明为 const 但在实现中忘了加 const 限定符，编译器会认为这是两个不同的函数（一个 const、一个非 const），链接时找不到 const 版本的实现会报错。这属于&quot;编译器是对的，但报错信息可能很晦涩&quot;的情况。</p><p><strong>验证</strong>: 这两个方法会在集成测试中被大量使用，不需要独立验证。</p><h3 id="step-4-编写-qemu-in-kernel-集成测试" tabindex="-1">Step 4: 编写 QEMU in-kernel 集成测试 <a class="header-anchor" href="#step-4-编写-qemu-in-kernel-集成测试" aria-label="Permalink to &quot;Step 4: 编写 QEMU in-kernel 集成测试&quot;">​</a></h3><p><strong>目标</strong>: 在 QEMU 内核环境中测试 PMM 的完整功能。</p><p><strong>设计思路</strong>: 测试文件是 <code>kernel/test/test_pmm.cpp</code>，作为 <code>big_kernel_test</code> 可执行文件的一部分运行。测试在 <code>main_test.cpp</code> 的 <code>kernel_main</code> 中被调度——在 PMM init 完成之后调用 <code>run_pmm_tests()</code>。</p><p>测试用例设计为六个。第一个验证初始化统计：total_page_count &gt; 0，free_page_count &gt; 0，free &lt;= total。第二个测试单页分配/释放循环：分配一页，检查返回地址非零且 4KB 对齐，检查 free_pages 减少了 1，释放后检查恢复。第三个测试批量分配/释放：连续分配 16 页，检查每页都非零且对齐，检查 free_pages 减少了 16，全部释放后检查恢复。第四个测试连续多页分配：调用 <code>alloc_pages(4)</code> 分配 4 个连续页，检查返回地址非零且对齐，释放后检查恢复。第五个测试 free_page(0) 的 no-op 行为：调用 <code>free_page(0)</code> 后 free_pages 不变。第六个测试 double-free 的 no-op 行为：分配一页，释放它，再次释放，第二次释放后 free_pages 不变。</p><p>每个测试用例都是一个独立的函数，放在独立的命名空间中（<code>test_pmm_init</code>、<code>test_pmm_alloc</code>、<code>test_pmm_bulk</code>、<code>test_pmm_contiguous</code>、<code>test_pmm_edge</code>），通过 <code>TEST_ASSERT_EQ</code>、<code>TEST_ASSERT_NE</code>、<code>TEST_ASSERT_GT</code>、<code>TEST_ASSERT_GE</code> 等宏做断言。入口函数 <code>run_pmm_tests()</code> 用 <code>TEST_SECTION</code> 和 <code>RUN_TEST</code> 宏组织测试的执行和报告。</p><p><strong>实现约束</strong>: 测试文件 include <code>big_kernel_test.h</code>（测试框架）和 <code>kernel/mm/pmm.hpp</code>。使用 <code>cinux::mm::g_pmm</code> 全局实例。在 <code>main_test.cpp</code> 中，PMM init 必须在 <code>run_pmm_tests()</code> 之前执行——也就是说 <code>g_pmm.init(*boot_info)</code> 要在所有 PMM 测试之前被调用。入口函数 <code>run_pmm_tests()</code> 声明为 <code>extern &quot;C&quot;</code> 以避免 C++ name mangling。</p><p><strong>踩坑预警</strong>: 测试中的断言宏（<code>TEST_ASSERT_EQ</code> 等）要求左右操作数的类型兼容——如果一个是 <code>uint64_t</code> 另一个是 <code>int</code>，可能会触发有符号/无符号比较警告。解决方法是在字面量后面加 <code>u</code> 后缀（比如 <code>0u</code> 而不是 <code>0</code>）。另外，测试中分配的页面必须在测试结束时全部释放——如果某个测试提前 return 了（比如断言失败后），忘记释放的页面会导致后续测试的 free_pages 计数不正确。虽然我们的测试框架在断言失败后通常会继续执行（而不是 abort），但保持&quot;谁分配谁释放&quot;的原则是好习惯。</p><p><strong>验证</strong>: 构建 <code>big_kernel_test</code> 并在 QEMU 中运行。PMM 测试部分应该输出类似：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=== PMM Tests (015) ===</span></span>
<span class="line"><span>  [PASS] test_init_and_stats</span></span>
<span class="line"><span>  [PASS] test_alloc_free_cycle</span></span>
<span class="line"><span>  [PASS] test_bulk_alloc_free</span></span>
<span class="line"><span>  [PASS] test_alloc_pages_contiguous</span></span>
<span class="line"><span>  [PASS] test_free_zero_noop</span></span>
<span class="line"><span>  [PASS] test_double_free_noop</span></span>
<span class="line"><span>=== 6 passed, 0 failed ===</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>如果任何测试失败，输出会显示期望值和实际值的差异。</p><h3 id="step-5-完善-host-端单元测试" tabindex="-1">Step 5: 完善 host 端单元测试 <a class="header-anchor" href="#step-5-完善-host-端单元测试" aria-label="Permalink to &quot;Step 5: 完善 host 端单元测试&quot;">​</a></h3><p><strong>目标</strong>: 在 host 端覆盖位图分配器的算法正确性。</p><p><strong>设计思路</strong>: 在上一章写好的 <code>parse_memory_map</code> 测试基础上，添加位图分配器相关的测试用例。由于 host 端无法使用真正的 PMM（它依赖内核的 linker symbol 和物理内存映射），我们在测试文件中重新实现一个 <code>TestPMM</code> 类——它复制了 PMM 的核心算法（位图操作、alloc_page、free_page、alloc_pages、free_pages），但使用普通的 <code>new</code> 分配位图而不是内核内存。</p><p>测试用例需要覆盖以下场景。第一个：单页分配返回 4KB 对齐的地址。第二个：1000 次连续分配/释放循环后 free_pages 计数恢复到初始值。第三个：所有页分配完毕后 alloc_page 返回 0（OOM）。第四个：free_page(0) 是 no-op。第五个：double-free 是 no-op。第六个：alloc_pages(4) 返回连续的物理地址。第七个：在碎片化内存（棋盘模式）上 alloc_pages(2) 失败。第八个：mark_free 和 mark_used 的计数正确，重复操作是 no-op。</p><p><strong>实现约束</strong>: 测试文件是 <code>test/unit/test_pmm.cpp</code>，使用 Cinux 自带的 <code>test_framework.h</code>（define <code>TEST_FRAMEWORK_IMPL</code> 来拉入实现）。<code>TestPMM</code> 类放在匿名命名空间中。编译为独立的可执行文件 <code>test_pmm</code>，在 <code>test/CMakeLists.txt</code> 中定义目标。编译定义中加 <code>CINUX_HOST_TEST</code> 宏——虽然当前的 PMM 测试不依赖这个宏，但保持和其他 host 测试的一致性是好的。</p><p><strong>踩坑预警</strong>: <code>TestPMM</code> 的构造函数接收的是&quot;总页数&quot;而不是&quot;总内存大小&quot;——如果你传入的是字节数而不是页数，位图会大得离谱。比如传入 128 * 1024 * 1024（128MB 的字节数）而不是 128 * 1024 * 1024 / 4096（128MB 的页数 = 32768），位图会尝试分配 16GB 的内存，直接 OOM。另外，<code>TestPMM</code> 的 <code>alloc_page</code> 方法中，页 0 对应的物理地址是 0——所以在构造测试时，应该从页 1 开始 mark_free（<code>mark_free(1, total_pages - 1)</code>），否则 <code>alloc_page</code> 可能返回 0 被误判为 OOM。</p><p><strong>验证</strong>: 运行 host 端测试：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build &amp;&amp; cd build &amp;&amp; ctest -L pmm --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所有 12 个测试用例（5 个 parse_memory_map + 7 个位图分配器 + 1 个 mark 计数）应该全部通过。如果有失败，ctest 会输出断言失败的具体位置和期望/实际值。</p><h3 id="step-6-更新构建系统和运行完整测试" tabindex="-1">Step 6: 更新构建系统和运行完整测试 <a class="header-anchor" href="#step-6-更新构建系统和运行完整测试" aria-label="Permalink to &quot;Step 6: 更新构建系统和运行完整测试&quot;">​</a></h3><p><strong>目标</strong>: 确保所有测试目标正确集成到构建系统中。</p><p><strong>设计思路</strong>: 需要在两个 CMakeLists.txt 中添加条目。首先是 <code>kernel/CMakeLists.txt</code>——在 <code>big_kernel_common</code> 库中添加 <code>mm/pmm.cpp</code>，在 <code>big_kernel_test</code> 可执行文件中添加 <code>test/test_pmm.cpp</code>。然后是 <code>test/CMakeLists.txt</code>——添加 <code>test_pmm</code> 可执行文件目标（编译 <code>unit/test_pmm.cpp</code>），设置 include 目录和编译定义，注册 ctest，最后把它加到 <code>test_host</code>、<code>test</code>、<code>test_verbose</code> 三个自定义目标的依赖列表中。</p><p><strong>实现约束</strong>: <code>test_pmm</code> 目标的 include 目录需要包含 <code>\${TEST_INCLUDE_DIRS}</code>（测试框架头文件路径）和 <code>\${CMAKE_SOURCE_DIR}</code>（项目根目录，用于 include <code>boot/boot_info.h</code>）。ctest 的标签设为 <code>pmm</code>，方便按标签运行。</p><p><strong>踩坑预警</strong>: 如果你忘了把 <code>test_pmm</code> 加入 <code>test_host</code> 目标的依赖列表，那么 <code>cmake --build build --target test_host</code> 不会编译 <code>test_pmm</code>——虽然单独运行 <code>ctest -L pmm</code> 会报 &quot;test executable not found&quot;。这是一个容易遗漏的步骤，因为每添加一个新的测试目标都需要在三个地方（<code>test_host</code>、<code>test</code>、<code>test_verbose</code>）手动加入依赖。另外，<code>big_kernel_test</code> 的源文件列表中也需要加入 <code>test/test_pmm.cpp</code>——如果你只加了 <code>mm/pmm.cpp</code> 到 <code>big_kernel_common</code> 而忘了加测试文件到 <code>big_kernel_test</code>，链接时会报 &quot;undefined reference to run_pmm_tests&quot;。</p><p><strong>验证</strong>: 运行完整的测试流程：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build &amp;&amp; cd build &amp;&amp; ctest --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所有测试标签（smoke、kprintf_format、gdt_idt、ata、elf_loader、big_kernel_loader、kprintf、pic、pit、font、console、framebuffer、keyboard、pmm）应该全部通过。特别关注 <code>pmm</code> 标签下的 12 个 host 端测试和 QEMU 内核测试中的 6 个 PMM 集成测试。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>构建并运行完整测试套件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build &amp;&amp; cd build &amp;&amp; ctest -L pmm --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Host 端测试应该输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Test project /path/to/build</span></span>
<span class="line"><span>    Start 1: pmm</span></span>
<span class="line"><span>1/1 Test #1: pmm ..............................   Passed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>QEMU in-kernel 测试需要通过 <code>test</code> 目标触发（会先跑 host 测试，然后启动 QEMU 运行内核测试）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmake --build build --target test-image</span></span>
<span class="line"><span>cmake --build build --target test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>在 QEMU 的串口输出中，PMM 测试部分应该显示 6 个 PASS。</p><p>如果你只想验证 PMM 不 crash，最简单的方式是运行正常的 big_kernel（不是 test 版本），看串口输出中是否有 <code>[PMM] Total: XXMB, Free: YYMB</code> 这行，以及后续的初始化是否正常继续。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>alloc_page 始终返回 0（OOM）</strong>: 首先检查 <code>free_pages_</code> 的值——如果在 init 完成后它就是 0，说明第五步（解锁可用区域）没有生效。用 kprintf 在 <code>mark_region_free</code> 调用前后打印 free_pages_ 的值来确认。如果 free_pages_ &gt; 0 但 alloc_page 仍然返回 0，说明 <code>bm_find_first_free</code> 的扫描有 bug——用 kprintf 打印位图的前几个字节，看是否全为 0xFF。</p><p><strong>连续分配总是失败</strong>: 如果 <code>alloc_pages(4)</code> 总是返回 0，可能的原因有两个。一是物理内存确实高度碎片化——不太可能在 QEMU 中发生（QEMU 的 E820 通常只报告一两个大的可用区域），但在某些 BIOS 配置下可能出现。二是 first-fit 扫描的 <code>run</code> 计数逻辑有 bug。调试方法是在扫描循环中加 kprintf，打印当前页号、bit 状态和 run 值，看扫描是否在正确的位置找到了连续空闲区域。</p><p><strong>host 测试中 TestPMM 的 free_count 不一致</strong>: 首先确认 <code>mark_free</code> 和 <code>mark_used</code> 的计数逻辑是否正确——它们应该只在状态确实发生变化时才更新 <code>free_pages_</code>。如果连续调用两次 <code>mark_free(10, 5)</code>，第二次不应该增加 free_pages_。在测试中加断言检查每一步操作后 free_count 的精确值。</p><p><strong>QEMU 测试中 PMM init crash</strong>: 这是上一章提到过的问题，但值得再强调一遍。最可能的原因是 linker symbol 取地址错误。在 <code>main_test.cpp</code> 中，PMM init 的调用和正式内核中的调用方式完全一样——<code>g_pmm.init(*boot_info)</code>——所以如果正式内核能正常 init 而测试内核 crash，问题可能出在测试内核的链接脚本中缺少了 <code>__kernel_stack_top</code> 符号的定义。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>关键点</th></tr></thead><tbody><tr><td>alloc_page</td><td>bm_find_first_free + bm_set，返回物理地址，0 = OOM</td></tr><tr><td>free_page</td><td>三层防御：phys==0、越界、double-free，全部静默 no-op</td></tr><tr><td>alloc_pages</td><td>count=1 走快速路径，count&gt;1 走 first-fit 线性扫描</td></tr><tr><td>free_pages</td><td>循环调用 free_page，依赖其防御性检查</td></tr><tr><td>OOM 标志</td><td>物理地址 0，因为物理地址 0（IVT）不在 PMM 管理范围内</td></tr><tr><td>Host 单元测试</td><td>TestPMM 类复制核心算法，覆盖 parse_memory_map + 分配器</td></tr><tr><td>QEMU 集成测试</td><td>真实 BootInfo 数据，6 个测试用例覆盖核心场景</td></tr><tr><td>构建集成</td><td>kernel/CMakeLists.txt + test/CMakeLists.txt 添加 PMM 目标</td></tr></tbody></table>`,87)])])}const m=o(c,[["render",d]]);export{u as __pageData,m as default};
